import Database from "better-sqlite3";
import fs from "node:fs";
import path from "node:path";

/**
 * This module is only ever imported from inside `routeLoader$` callbacks,
 * which are server-only QRL segments in Qwik City. As a result, none of
 * this code (including the `better-sqlite3` import) is included in the
 * client bundle.
 */

export interface Product {
  id: number;
  name: string;
  category: string;
  price: number;
  stock: number;
}

export type SortColumn = "name" | "category" | "price" | "stock";
export type SortDir = "asc" | "desc";

export const ALLOWED_SORT_COLUMNS: SortColumn[] = [
  "name",
  "category",
  "price",
  "stock",
];

export interface QueryOptions {
  q: string;
  sort: SortColumn;
  dir: SortDir;
  page: number;
  pageSize: number;
}

export interface QueryResult {
  rows: Product[];
  total: number;
}

let dbInstance: Database.Database | null = null;

function seedIfEmpty(instance: Database.Database) {
  const { count } = instance
    .prepare("SELECT COUNT(*) as count FROM products")
    .get() as { count: number };

  if (count > 0) return;

  const jsonPath = path.join(process.cwd(), "data", "products.json");
  const raw = fs.readFileSync(jsonPath, "utf-8");
  const products: Product[] = JSON.parse(raw);

  const insert = instance.prepare(
    `INSERT INTO products (id, name, category, price, stock)
     VALUES (@id, @name, @category, @price, @stock)`,
  );

  const insertMany = instance.transaction((items: Product[]) => {
    for (const item of items) insert.run(item);
  });

  insertMany(products);
}

export function getDb(): Database.Database {
  if (dbInstance) return dbInstance;

  const dataDir = path.join(process.cwd(), "data");
  if (!fs.existsSync(dataDir)) {
    fs.mkdirSync(dataDir, { recursive: true });
  }

  const dbPath = path.join(dataDir, "products.sqlite");
  const instance = new Database(dbPath);
  instance.pragma("journal_mode = WAL");

  instance.exec(`
    CREATE TABLE IF NOT EXISTS products (
      id INTEGER PRIMARY KEY,
      name TEXT NOT NULL,
      category TEXT NOT NULL,
      price REAL NOT NULL,
      stock INTEGER NOT NULL
    )
  `);

  seedIfEmpty(instance);

  dbInstance = instance;
  return dbInstance;
}

export function queryProducts(options: QueryOptions): QueryResult {
  const database = getDb();

  const sort = ALLOWED_SORT_COLUMNS.includes(options.sort)
    ? options.sort
    : "name";
  const dir = options.dir === "desc" ? "DESC" : "ASC";
  const page = Math.max(1, Math.floor(options.page) || 1);
  const pageSize = Math.max(1, Math.floor(options.pageSize) || 10);
  const offset = (page - 1) * pageSize;

  const hasSearch = options.q.trim().length > 0;
  const whereClause = hasSearch ? "WHERE name LIKE @q ESCAPE '\\'" : "";

  const escapedQ = options.q
    .replace(/\\/g, "\\\\")
    .replace(/%/g, "\\%")
    .replace(/_/g, "\\_");

  const params: Record<string, unknown> = hasSearch
    ? { q: `%${escapedQ}%` }
    : {};

  const totalRow = database
    .prepare(`SELECT COUNT(*) as count FROM products ${whereClause}`)
    .get(params) as { count: number };

  // Column name is validated against an allow-list above, so it is safe to
  // interpolate directly into the SQL string.
  const rows = database
    .prepare(
      `SELECT id, name, category, price, stock
       FROM products
       ${whereClause}
       ORDER BY ${sort} ${dir}
       LIMIT @limit OFFSET @offset`,
    )
    .all({ ...params, limit: pageSize, offset }) as Product[];

  return { rows, total: totalRow.count };
}

import { component$, useSignal, useVisibleTask$ } from "@builder.io/qwik";
import {
  routeLoader$,
  useLocation,
  useNavigate,
  Link,
  type DocumentHead,
} from "@builder.io/qwik-city";
import {
  queryProducts,
  ALLOWED_SORT_COLUMNS,
  type SortColumn,
  type SortDir,
} from "~/lib/db";

export const useProductsLoader = routeLoader$((requestEvent) => {
  const url = requestEvent.url;

  const q = url.searchParams.get("q") ?? "";

  const sortParam = url.searchParams.get("sort") ?? "name";
  const sort: SortColumn = (
    ALLOWED_SORT_COLUMNS as readonly string[]
  ).includes(sortParam)
    ? (sortParam as SortColumn)
    : "name";

  const dirParam = url.searchParams.get("dir") ?? "asc";
  const dir: SortDir = dirParam === "desc" ? "desc" : "asc";

  const pageParam = parseInt(url.searchParams.get("page") ?? "1", 10);
  const page = Number.isFinite(pageParam) && pageParam > 0 ? pageParam : 1;

  const pageSizeParam = parseInt(url.searchParams.get("pageSize") ?? "10", 10);
  const pageSize =
    Number.isFinite(pageSizeParam) && pageSizeParam > 0 ? pageSizeParam : 10;

  const { rows, total } = queryProducts({ q, sort, dir, page, pageSize });
  const totalPages = Math.max(1, Math.ceil(total / pageSize));

  return { rows, total, totalPages, q, sort, dir, page, pageSize };
});

export default component$(() => {
  const data = useProductsLoader();
  const loc = useLocation();
  const nav = useNavigate();

  const searchTerm = useSignal(data.value.q);

  // Debounce the search box: wait ~300ms after the user stops typing before
  // pushing the new `q` value into the URL (which re-runs the loader).

  useVisibleTask$(({ track, cleanup }) => {
    const value = track(() => searchTerm.value);

    const timer = setTimeout(() => {
      const url = new URL(loc.url);

      if (value) {
        url.searchParams.set("q", value);
      } else {
        url.searchParams.delete("q");
      }
      url.searchParams.set("page", "1");

      nav(`${url.pathname}${url.search}`);
    }, 300);

    cleanup(() => clearTimeout(timer));
  });

  const buildUrl = (
    overrides: Record<string, string | number | undefined>,
  ) => {
    const url = new URL(loc.url);
    for (const [key, value] of Object.entries(overrides)) {
      if (value === undefined || value === "") {
        url.searchParams.delete(key);
      } else {
        url.searchParams.set(key, String(value));
      }
    }
    return `${url.pathname}${url.search}`;
  };

  const sortHeader = (column: SortColumn, label: string) => {
    const isActive = data.value.sort === column;
    const nextDir: SortDir = isActive && data.value.dir === "asc" ? "desc" : "asc";
    const indicator = isActive ? (data.value.dir === "asc" ? " ▲" : " ▼") : "";

    return (
      <th>
        <Link href={buildUrl({ sort: column, dir: nextDir, page: 1 })}>
          {label}
          {indicator}
        </Link>
      </th>
    );
  };

  const prevPage = Math.max(1, data.value.page - 1);
  const nextPage = Math.min(data.value.totalPages, data.value.page + 1);

  return (
    <div>
      <h1>Products</h1>

      <div>
        <input
          type="text"
          placeholder="Search by name..."
          value={searchTerm.value}
          onInput$={(_, el) => {
            searchTerm.value = el.value;
          }}
        />
      </div>

      <p>Total: {data.value.total}</p>

      <table>
        <thead>
          <tr>
            {sortHeader("name", "Name")}
            {sortHeader("category", "Category")}
            {sortHeader("price", "Price")}
            {sortHeader("stock", "Stock")}
          </tr>
        </thead>
        <tbody>
          {data.value.rows.map((row) => (
            <tr key={row.id}>
              <td>{row.name}</td>
              <td>{row.category}</td>
              <td>{row.price}</td>
              <td>{row.stock}</td>
            </tr>
          ))}
        </tbody>
      </table>

      <div>
        <Link
          href={buildUrl({ page: prevPage })}
          aria-disabled={data.value.page <= 1}
        >
          Previous
        </Link>{" "}
        <span>
          Page {data.value.page} of {data.value.totalPages}
        </span>{" "}
        <Link
          href={buildUrl({ page: nextPage })}
          aria-disabled={data.value.page >= data.value.totalPages}
        >
          Next
        </Link>
      </div>
    </div>
  );
});

export const head: DocumentHead = {
  title: "Products",
};
